<x-app-layout title="Semester"><div class="space-y-6"><section class="card"><div class="card-body flex flex-col gap-4 md:flex-row md:items-center md:justify-between"><div><h2 class="text-lg font-bold text-emerald-950">Daftar Semester</h2><p class="text-sm text-slate-500">Semester harus terhubung dengan tahun ajaran. Hanya satu semester operasional yang aktif.</p></div>@can('semesters.create')<a href="{{ route('semesters.create') }}" class="btn btn-primary">Tambah Semester</a>@endcan</div></section><form method="get" class="card"><div class="card-body grid gap-3 md:grid-cols-2"><select name="academic_year_id"><option value="">Semua Tahun Ajaran</option>@foreach($years as $year)<option value="{{ $year->id }}" @selected(request('academic_year_id')==$year->id)>{{ $year->name }}</option>@endforeach</select><button class="btn btn-secondary">Terapkan Filter</button></div></form>@if($semesters->isEmpty())<div class="empty-state">Belum ada semester. Tambahkan semester Ganjil atau Genap pada tahun ajaran aktif.</div>@else<div class="table-wrap"><table class="data-table"><thead><tr><th>Semester</th><th>Tahun Ajaran</th><th>Periode</th><th>Status</th><th>Aksi</th></tr></thead><tbody>@foreach($semesters as $semester)<tr><td>{{ $semester->name }}</td><td>{{ $semester->academicYear?->name }}</td><td>{{ $semester->starts_on->format('d/m/Y') }} - {{ $semester->ends_on->format('d/m/Y') }}</td><td><span @class(['badge',$semester->is_active?'badge-success':'badge-muted'])>{{ $semester->is_active?'Aktif':'Tidak Aktif' }}</span></td><td class="flex flex-wrap gap-2"><a class="btn btn-secondary px-3 py-1.5" href="{{ route('semesters.show',$semester) }}">Detail</a>@can('semesters.update')<a class="btn btn-secondary px-3 py-1.5" href="{{ route('semesters.edit',$semester) }}">Ubah</a>@endcan @can('semesters.activate')<form method="post" action="{{ $semester->is_active ? route('semesters.deactivate',$semester) : route('semesters.activate',$semester) }}">@csrf @method('patch')<button class="btn btn-secondary px-3 py-1.5" onclick="return confirm('Ubah status semester ini?')">{{ $semester->is_active?'Nonaktifkan':'Aktifkan' }}</button></form>@endcan</td></tr>@endforeach</tbody></table></div>{{ $semesters->links() }}@endif</div></x-app-layout>
